onClick:
{{
(
  appsmith.store.modoSP === "MODIFICAR"
    ? qrySPModificar.run()
    : qrySPCrear.run()
)
.then(async () => {

if (appsmith.store.modoSP === "MODIFICAR") {

  await storeValue(
    "idSPImpresion",
    appsmith.store.idSPModificar
  );

} else {

  await storeValue(
    "idSPImpresion",
    qrySPCrear.data?.[0]?.id_solicitud_pago
  );

}

  showAlert(
    appsmith.store.modoSP === "MODIFICAR"
      ? 'Solicitud modificada: ' + inpNumeroSP.text
      : 'Solicitud creada: ' + qrySPCrear.data[0].numero_solicitud_pago,
    'success'
  );

  // Limpiar detalle
  await storeValue("detalleSP", []);

  // Limpiar encabezado creación
  await storeValue("idProyectoSP", null);
  await storeValue("idSuplidorSP", null);
  await storeValue("idMonedaSP", null);

  // Salir de modo modificación
  await storeValue("modoSP", null);
  await storeValue("idSPModificar", null);
  await storeValue("encabezadoSP", null);

  // Limpiar widgets
  resetWidget("inpID_SP");
  resetWidget("inpNumeroSP");

  resetWidget("inpConceptoSP");

  resetWidget("inpRetIbisSP");
  resetWidget("inpRetDGIISP");
  resetWidget("inpRetGarantiaSP");
  resetWidget("inpRetTSSSP");

  resetWidget("selOtraMonedaSP");
  resetWidget("selOtraMonedaCodigoSP");
  resetWidget("inpTasaOtraMoneda");

  resetWidget("inpFCparaSPlinea");
  resetWidget("inpValorSolicitadoSP");

})
.catch((err) => {

  showAlert(
    err.message,
    'error'
  );

});
}}
